# Production-scale few-shot cricket analysis with safety and caching
from openai import OpenAI
import hashlib

client = OpenAI(api_key="sk-...")

# Few-shot examples (diverse bowler types)
cricket_examples = [
    {"bowler": "Jasprit Bumrah", "style": "Fast yorker specialist", "analysis": "Death overs, precision angles, minimal run-up"},
    {"bowler": "Ravichandran Ashwin", "style": "Off-spinner", "analysis": "Variation, flight control, experience-based deception"},
    {"bowler": "Pat Cummins", "style": "Fast-medium aggressor", "analysis": "Pace, short balls, seam movement, physical presence"}
]

def analyze_bowler_zero_shot(bowler_name: str) -> str:
    """Zero-shot: no examples, relies on model knowledge."""
    response = client.chat.completions.create(
        model="gpt-4",
        messages=[
            {"role": "system", "content": "You are a cricket analyst."},
            {"role": "user", "content": f"Analyze {bowler_name}'s bowling style in 50 words."}
        ],
        temperature=0.7,
        max_tokens=60
    )
    return response.choices[0].message.content

def analyze_bowler_few_shot(bowler_name: str) -> str:
    """Few-shot: 3 diverse examples improve accuracy."""
    prompt = "Analyze bowling style in this format: [Name]: [Style] | Analysis: [insight].\n\n"
    for ex in cricket_examples:
        prompt += f"{ex['bowler']}: {ex['style']} | Analysis: {ex['analysis']}\n"
    prompt += f"\nNow analyze: {bowler_name}:"

    response = client.chat.completions.create(
        model="gpt-4",
        messages=[
            {"role": "system", "content": "You are a cricket analyst."},
            {"role": "user", "content": prompt}
        ],
        temperature=0.7,
        max_tokens=80
    )
    return response.choices[0].message.content

# Production safeguard: prompt hash caching to reduce redundant API calls
def cached_analysis(bowler_name: str, use_few_shot: bool = True) -> str:
    cache_key = hashlib.md5(f"{bowler_name}_{use_few_shot}".encode()).hexdigest()
    # In production, check Redis/DynamoDB here
    if use_few_shot:
        return analyze_bowler_few_shot(bowler_name)
    return analyze_bowler_zero_shot(bowler_name)

# Example: Production query at scale
print(cached_analysis("Yuzvendra Chahal", use_few_shot=True))
